class Solution {
    public String baseNeg2(int n) {
        if (n == 0) return "0";
        StringBuilder sb = new StringBuilder();
        while (n != 0) {
            int remainder = n % (-2);
            n /= -2;
            if (remainder < 0) {
                n++;
                remainder += 2;
            }
            sb.append(remainder == 0 ? '0' : '1');
        }
        return sb.reverse().toString();
    }
}
```
